import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import SideNav from "./SideNav";
import VIDYAPage from "../pages/VIDYA";
import "./PageLayout.css";

export default function PageLayout({ userName, children }) {
  const navigate = useNavigate();
  const [collapsed, setCollapsed] = useState(false);
  const [vidyaOpen, setVidyaOpen] = useState(false);
  const onLogout = () => navigate('/login');

  return (
    <div className="page-layout">
      <SideNav
        userName={userName}
        onLogout={onLogout}
        collapsed={collapsed}
        setCollapsed={setCollapsed}
      />
      <div className={`page-content ${collapsed ? "collapsed" : ""}`}>
        {children}
      </div>

      {/* Floating VIDYA AI Button */}
      <button
        className="vidya-fab"
        onClick={() => setVidyaOpen(o => !o)}
        title="Open VIDYA AI"
        aria-label="Open VIDYA AI"
      >
        <span className="vidya-fab-icon">{vidyaOpen ? "✕" : "🤖"}</span>
        {!vidyaOpen && <span className="vidya-fab-label">VIDYA AI</span>}
      </button>

      {/* VIDYA AI Drawer */}
      {vidyaOpen && (
        <div className="vidya-drawer">
          <VIDYAPage userName={userName} isFloating />
        </div>
      )}
    </div>
  );
}
